form:Form.form:Scripts:
		var CLASS_TREE=null;

function LoadChilds(objTree, objGroup)
{
	nSQL = GetProxy().SQLService();

	var id=objGroup.FullId.split("/"); id=id[id.length-1];
	if(id==".")
		id = "";
	var resultxt=nSQL.Get(Ctrl("main").getResource("qry_estructura"), "<PARAM id=\""+id+"\" />");
  objTree.SetXML(objGroup.FullId, resultxt);
}

function onClick()
{                                          
	var fullid=Ctrl("oi_estructura_full").GetXValue();


	if (CLASS_TREE.GetGroup(fullid) && fullid!=".") 
	{
		var id=fullid.split("/"); 
		id=id[id.length-1];
		if (id==".") id="";

 		Ctrl("oi_estructura").SetXValue(id);
		CtrlEnabled("ACCEPT",true);
	} else                               
 	{
 		CtrlEnabled("ACCEPT",false);      
 		Ctrl("oi_estructura").SetXValue("");
 	}
}

function onLoad()
{       
	nSQL = GetProxy().SQLService();

	var oi_estructura=Ctrl("oi_estructura").GetXValue();
	var fullId=(oi_estructura==""?".":nSQL.GetOBJ(Ctrl("main").getResource("qry_find_estructura"), "<PARAM id=\""+oi_estructura+"\" />").fullId);

	var resultxt=nSQL.Get(Ctrl("main").getResource("qry_clases"), "<PARAM oi_clase_org=\""+Ctrl("oi_clase_org").GetXValue()+"\" />");
	CLASS_TREE=clsClientTree("contESTR","oi_estructura_full","CLOCK.ico","folder-close.ico","folder.ico","item.ico",true,LoadChilds,null,onClick,1000);
	CLASS_TREE.SetXML(null, resultxt);

	Ctrl("oi_estructura_full").SetXValue(fullId);
	CLASS_TREE.SetSelectedId(fullId);
	if(fullId==".") CLASS_TREE.ClickExpGroup(".");

	//alert(fullId);
	CLASS_TREE.ClickExpGroup(fullId);
	onClick();
}    

function SearchText()
{                   
	nSQL = GetProxy().SQLService();

	if (Ctrl("buscar").GetXValue()!='')
	{
		var P=new NomadXML("PARAM");
		P.SetAttr("oi_clase_org", Ctrl("oi_clase_org").GetXValue());
		P.SetAttr("txt_find", Ctrl("buscar").GetXValue());

		P=new NomadXML(nSQL.Get(Ctrl("main").getResource("qry_find"), P.ToString()));
		if (P.GetAttr("mode")!='')
		{                          
			Ctrl("oi_estructura_full").SetXValue(P.GetAttr("fullid"))
			CLASS_TREE.SetSelectedId(P.GetAttr("fullid"));
			CLASS_TREE.ClickExpGroup(P.GetAttr("fullid"));    
			onClick();
		}
	}
}
